INSERT INTO `tipos_servicio` VALUES
(1,'Regular Interurbano','Servicio de transporte entre ciudades con paradas programadas. Conecta diferentes municipios y departamentos.',150.00,'fas fa-road','#10b981',1,'2026-04-10 12:17:09','2026-04-10 12:17:09'),
(2,'Directo o Express','Servicio rápido con pocas paradas, diseñado para llegar a tu destino en el menor tiempo posible. Sin paradas intermedias.',250.00,'fas fa-bolt','#f59e0b',1,'2026-04-10 12:17:09','2026-04-10 12:17:09'),
(3,'Renta','Alquiler de autobús completo para eventos, excursiones o viajes grupales. Servicio personalizado según tus necesidades.',5000.00,'fas fa-clipboard','#8b5cf6',1,'2026-04-10 12:17:09','2026-04-10 12:17:09'),
(4,'Turístico','Servicio especial para tours y recorridos turísticos con guía incluido. Incluye paradas en puntos de interés.',400.00,'fas fa-camera','#ec4899',1,'2026-04-10 12:17:10','2026-04-10 12:17:10'),
(5,'Ejecutivo','Servicio premium con asientos confortables, WiFi y climatización avanzada. Ideal para viajes de negocios.',320.00,'fas fa-briefcase','#667eea',1,'2026-04-10 12:17:10','2026-04-10 12:17:10');
